import java.io.*;
import java.util.*;
public class Main{
    static class Node{int val;Node left,right;Node(int v){val=v;}}
    static Node build(int[]pre,int pl,int pr,int[]in,int il,int ir,Map<Integer,Integer>mp){
        if(pl>pr) return null;
        int rootVal=pre[pl];
        int idx=mp.get(rootVal);
        int leftSize=idx-il;
        Node node=new Node(rootVal);
        node.left=build(pre,pl+1,pl+leftSize,in,il,idx-1,mp);
        node.right=build(pre,pl+leftSize+1,pr,in,idx+1,ir,mp);
        return node;
    }
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out=new StringBuilder();
        int T=Integer.parseInt(br.readLine().trim());
        while(T-- > 0){
            int N=Integer.parseInt(br.readLine().trim());
            int[] pre=new int[N];
            int[] in=new int[N];
            StringTokenizer st=new StringTokenizer(br.readLine());
            for(int i=0;i<N;i++) pre[i]=Integer.parseInt(st.nextToken());
            st=new StringTokenizer(br.readLine());
            for(int i=0;i<N;i++) in[i]=Integer.parseInt(st.nextToken());
            Map<Integer,Integer> mp=new HashMap<>(N*2);
            for(int i=0;i<N;i++) mp.put(in[i],i);
            Node root=build(pre,0,N-1,in,0,N-1,mp);
            out.append("Well Done!\n");
        }
        System.out.print(out.toString());
    }
}

