const fs=require('fs');
const data=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let p=0;
const T=Number(data[p++]);
let out=[];
function build(pre,pl,pr,inord,il,ir,map){
  if(pl>pr) return null;
  const root=pre[pl];
  const i=map.get(root);
  const left=i-il;
  const node={val:root,left:null,right:null};
  node.left=build(pre,pl+1,pl+left,inord,il,i-1,map);
  node.right=build(pre,pl+left+1,pr,inord,i+1,ir,map);
  return node;
}
for(let tc=0;tc<T;tc++){
  const N=Number(data[p++]);
  const pre=new Array(N);
  const inord=new Array(N);
  for(let i=0;i<N;i++) pre[i]=Number(data[p++]);
